watch(() => magicPillMax.value, (maxCount) => { const limit = Math.max(normalizePositiveInt(maxCount, 1), 1); pillCraftQuantity.value = String(Math.min(normalizePositiveInt(pillCraftQuantity.value, 1), limit)); }, { immediate: true });
